<!DOCTYPE html>
<html lang="en">
<head>
    <meta charset="UTF-8">
    <meta name="viewport" content="width=device-width, initial-scale=1.0">
    <title>Ubuntu Desktop Environment</title>
    <style>
        :root {
            --bg-color: #300a24; /* Ubuntu Dark Purple */
            --accent-color: #772953;
            --taskbar-bg: rgba(0, 0, 0, 0.8);
            --window-bg: #fdfdfd;
            --title-bar-bg: #e0e0e0;
            --text-color: #333;
        }

        * { box-sizing: border-box; margin: 0; padding: 0; }

        body, html {
            height: 100%;
            overflow: hidden;
            font-family: 'Segoe UI', Tahoma, Geneva, Verdana, sans-serif;
        }

        #desktop {
            width: 100vw;
            height: 100vh;
            background: linear-gradient(135deg, #300a24 0%, #5e2750 100%);
            position: relative;
            overflow: hidden;
        }

        /* Taskbar / Dock */
        #taskbar {
            position: fixed;
            bottom: 0;
            width: 100%;
            height: 60px;
            background: var(--taskbar-bg);
            backdrop-filter: blur(10px);
            display: flex;
            justify-content: center;
            align-items: center;
            gap: 20px;
            border-top: 1px solid rgba(255,255,255,0.1);
            z-index: 9999;
        }

        #taskbar button {
            padding: 10px 20px;
            background: #4a1d3e;
            color: white;
            border: none;
            border-radius: 5px;
            cursor: pointer;
            transition: background 0.2s;
        }

        #taskbar button:hover {
            background: var(--accent-color);
        }

        /* Window Styling */
        .window {
            position: absolute;
            min-width: 360px;
            min-height: 240px;
            background: var(--window-bg);
            border-radius: 8px;
            box-shadow: 0 10px 30px rgba(0,0,0,0.5);
            display: flex;
            flex-direction: column;
            overflow: hidden;
            border: 1px solid #999;
        }

        .window-header {
            padding: 8px 12px;
            background: var(--title-bar-bg);
            display: flex;
            justify-content: space-between;
            align-items: center;
            cursor: move;
            border-bottom: 1px solid #ccc;
        }

        .window-header h3 {
            font-size: 0.9rem;
            color: #444;
        }

        .win-close {
            background: #ff5f56;
            border: none;
            border-radius: 50%;
            width: 20px;
            height: 20px;
            cursor: pointer;
            font-weight: bold;
        }

        .window-content {
            flex: 1;
            padding: 15px;
            overflow: auto;
        }

        /* Files App Styling */
        #files-path {
            margin-bottom: 10px;
            font-weight: bold;
            color: #666;
            font-size: 0.8rem;
        }

        .fs-list {
            display: grid;
            grid-template-columns: repeat(auto-fill, minmax(100px, 1fr));
            gap: 15px;
        }

        .fs-item {
            text-align: center;
            cursor: pointer;
            padding: 10px;
            border-radius: 4px;
            transition: background 0.2s;
        }

        .fs-item:hover {
            background: #e8e8e8;
        }

        .fs-icon {
            font-size: 2rem;
            display: block;
            margin-bottom: 5px;
        }

        #files-up {
            margin-bottom: 10px;
            padding: 5px 10px;
            cursor: pointer;
            background: #ddd;
            border: none;
            border-radius: 3px;
        }

        /* Notepad App Styling */
        #tabs {
            display: flex;
            gap: 2px;
            background: #ccc;
            padding: 5px 5px 0 5px;
        }

        .tab {
            padding: 8px 15px;
            background: #bbb;
            border-radius: 5px 5px 0 0;
            cursor: pointer;
            font-size: 0.8rem;
            max-width: 120px;
            white-space: nowrap;
            overflow: hidden;
            text-overflow: ellipsis;
        }

        .tab.active {
            background: var(--window-bg);
            font-weight: bold;
            border: 1px solid #ccc;
            border-bottom: none;
        }

        #editor {
            width: 100%;
            height: calc(100% - 40px);
            border: none;
            resize: none;
            padding: 10px;
            font-family: monospace;
            outline: none;
        }

        #new-tab {
            margin-bottom: 5px;
            padding: 5px;
            cursor: pointer;
        }

        .hidden { display: none !important; }
    </style>
</head>
<body>

<div id="desktop">
    <!-- Files Window -->
    <div id="files-window" class="window hidden" style="top: 100px; left: 100px;">
        <div class="window-header">
            <h3>File Explorer</h3>
            <button class="win-close">×</button>
        </div>
        <div class="window-content">
            <button id="files-up">.. (Up)</button>
            <div id="files-path">/</div>
            <div id="files-list" class="fs-list"></div>
        </div>
    </div>

    <!-- Notepad Window -->
    <div id="notepad-window" class="window hidden" style="top: 150px; left: 450px;">
        <div class="window-header">
            <h3>Notepad</h3>
            <button class="win-close">×</button>
        </div>
        <div class="window-content" style="padding: 0;">
            <div id="tabs"></div>
            <button id="new-tab">+ New Tab</button>
            <textarea id="editor"></textarea>
        </div>
    </div>

    <div id="taskbar">
        <button id="open-files">Files</button>
        <button id="open-notepad">Notepad</button>
    </div>
</div>

<script>
    /** FILE SYSTEM DATA **/
    const fsData = {
        "bin": {},
        "etc": {},
        "home": {
            "user": {
                "Documents": {},
                "Downloads": {},
                "Pictures": {}
            }
        },
        "usr": {},
        "var": {}
    };

    let currentPath = []; // Array of folder names

    /** NOTEPAD STATE **/
    let tabs = JSON.parse(localStorage.getItem('notepad_tabs')) || [
        { id: Date.now(), title: 'Untitled', content: '' }
    ];
    let activeTabId = tabs[0].id;

    /** DOM ELEMENTS **/
    const filesWin = document.getElementById('files-window');
    const notepadWin = document.getElementById('notepad-window');
    const filesList = document.getElementById('files-list');
    const filesPathDisplay = document.getElementById('files-path');
    const editor = document.getElementById('editor');
    const tabsContainer = document.getElementById('tabs');

    /** WINDOW MANAGEMENT **/
    function toggleWindow(win, show) {
        if (show) win.classList.remove('hidden');
        else win.classList.add('hidden');
    }

    document.querySelectorAll('.win-close').forEach(btn => {
        btn.addEventListener('click', (e) => {
            const win = e.target.closest('.window');
            toggleWindow(win, false);
        });
    });

    document.getElementById('open-files').onclick = () => toggleWindow(filesWin, true);
    document.getElementById('open-notepad').onclick = () => {
        renderNotepad();
        toggleWindow(notepadWin, true);
    };

    // Draggable Logic
    document.querySelectorAll('.window').forEach(win => {
        const header = win.querySelector('.window-header');
        let isDragging = false;
        let offsetX, offsetY;

        header.onmousedown = (e) => {
            isDragging = true;
            offsetX = e.clientX - win.offsetLeft;
            offsetY = e.clientY - win.offsetTop;
            win.style.zIndex = 1000; // Bring to front
        };

        document.onmousemove = (e) => {
            if (!isDragging) return;
            win.style.left = (e.clientX - offsetX) + 'px';
            win.style.top = (e.clientY - offsetY) + 'px';
        };

        document.onmouseup = () => {
            isDragging = false;
        };
    });

    /** FILES APP LOGIC **/
    function renderFiles() {
        filesList.innerHTML = '';
        const currentDir = currentPath.reduce((obj, key) => obj[key], fsData);

        filesPathDisplay.innerText = '/' + currentPath.join('/');

        Object.keys(currentDir).forEach(name => {
            const item = document.createElement('div');
            item.className = 'fs-item';
            const isDir = typeof currentDir[name] === 'object' && Object.keys(currentDir[name]).length >= 0;
            // Note: In our structure, everything is an object (folder) or empty. 
            // For simplicity in this demo, we treat all keys as folders unless they are specific files.
            // Let's assume if it has nested keys it's a folder.
            const isFolder = Object.keys(currentDir[name]).length >= 0 && name !== 'bin' && name !== 'etc'; 
            // Actually, let's just treat everything as a directory for the required structure.

            item.innerHTML = `<span class="fs-icon">${isFolder ? '📁' : '📄'}</span>${name}`;

            item.ondblclick = () => {
                if (typeof currentDir[name] === 'object') {
                    currentPath.push(name);
                    renderFiles();
                }
            };
            filesList.appendChild(item);
        });
    }

    document.getElementById('files-up').onclick = () => {
        if (currentPath.length > 0) {
            currentPath.pop();
            renderFiles();
        }
    };

    // Initial Files Render
    renderFiles();

    /** NOTEPAD APP LOGIC **/
    function renderNotepad() {
        tabsContainer.innerHTML = '';
        tabs.forEach(tab => {
            const tabEl = document.createElement('div');
            tabEl.className = `tab ${tab.id === activeTabId ? 'active' : ''}`;
            tabEl.innerText = tab.title;
            tabEl.onclick = () => switchTab(tab.id);
            tabsContainer.appendChild(tabEl);
        });

        const activeTab = tabs.find(t => t.id === activeTabId);
        editor.value = activeTab ? activeTab.content : '';
    }

    function switchTab(id) {
        activeTabId = id;
        renderNotepad();
    }

    document.getElementById('new-tab').onclick = () => {
        const newId = Date.now();
        tabs.push({ id: newId, title: 'New Tab', content: '' });
        activeTabId = newId;
        renderNotepad();
        saveTabs();
    };

    editor.oninput = (e) => {
        const activeTab = tabs.find(t => t.id === activeTabId);
        if (activeTab) {
            activeTab.content = e.target.value;
            saveTabs();
        }
    };

    function saveTabs() {
        localStorage.setItem('notepad_tabs', JSON.stringify(tabs));
    }

    // Initial Notepad Load
    renderNotepad();

</script>
</body>
</html>
